   481→  }
   482→  UnlockSemaphoreInfo(mime_semaphore);
   483→  qsort((void *) aliases,(size_t) i,sizeof(*aliases),MimeInfoCompare);
   484→  aliases[i]=(MimeInfo *) NULL;
